mapper.select:
SELECT * FROM (
    SELECT m.*,
           mf.file_id AS fileId,
           f.ori_name AS fileName
    FROM message m
    LEFT JOIN message_file mf ON m.message_id = mf.message_id
    LEFT JOIN file f ON mf.file_id = f.file_id
    WHERE m.chat_room_id = #{chatRoomId}

        AND m.message_id < #{lastMessageId}

    ORDER BY m.message_id DESC
    LIMIT #{size}
) sub
ORDER BY message_id ASC

mapper.update:
UPDATE message
SET is_deleted = true
WHERE message_id = #{messageId}
